# ROBUSTNESS PHASE E — Data integrity and runtime behavioral correctness
# Manually written, not generated by testgen.py. Do not delete.
#
# Validates the inline ECU simulator's *behavioral* correctness beyond NRC
# codes: write/read-back of DID values, DTC lifecycle (set → read → clear →
# verify), session and security state isolation, and protocol response format.
# Every test calls _inline_handle directly — no xaloqi-tester required.
#
# Run: pytest test_robustness_E_data_integrity.py -v
from __future__ import annotations

import os
import sys
from typing import Optional

import pytest

sys.path.insert(0, os.path.dirname(__file__))
from conftest import (
    _EcuSimulator,
    _InlineEcuState,
    _LEVEL_KEYS,
    _inline_handle,
    ALGO_KEY_LEN,
    ALGO_SEED_LEN,
    NRC_CONDITIONS_NOT_CORRECT,
    NRC_INCORRECT_MSG_LEN,
    NRC_REQUEST_OUT_OF_RANGE,
    NRC_SECURITY_ACCESS_DENIED,
    NRC_SERVICE_NOT_SUPPORTED_IN_SESSION,
    SESSION_DEFAULT,
    SESSION_EXTENDED,
    SESSION_PROGRAMMING,
    SID_DIAGNOSTIC_SESSION_CONTROL,
    SID_ECU_RESET,
    SID_NEGATIVE_RESPONSE,
    SID_READ_DATA_BY_ID,
    SID_READ_DTC_INFO,
    SID_ROUTINE_CONTROL,
    SID_SECURITY_ACCESS,
    SID_TESTER_PRESENT,
    SID_WRITE_DATA_BY_ID,
)

SID_CLEAR_DTC = 0x14

# basic_ecu DID catalogue (from diagnostics_config.yaml)
DID_VIN        = 0xF190   # 17 bytes, read-only,  min_session=default
DID_ECU_SERIAL = 0xF18C   # 4 bytes,  read-only,  min_session=default
DID_SPARE_PART = 0xF187   # 11 bytes, read+write, min_session=extended, write_sec=1
DID_CUSTOM_0C  = 0x0C00   # 2 bytes,  read-only,  min_session=default
DID_CUSTOM_05  = 0x0500   # 1 byte,   read-only,  min_session=default

# basic_ecu routine catalogue
RID_SELFTEST   = 0xFF00   # min_session=extended, sec_level=0, {start, results}
RID_FF01       = 0xFF01   # min_session=extended, sec_level=1, {start}
RID_FF10       = 0xFF10   # min_session=programming, sec_level=1, {start, results}


def _sim() -> _InlineEcuState:
    return _InlineEcuState()


def _req(state: _InlineEcuState, pdu: bytes) -> Optional[bytes]:
    return _inline_handle(pdu, state, False)


def _session(state: _InlineEcuState, s: int) -> None:
    _inline_handle(bytes([SID_DIAGNOSTIC_SESSION_CONTROL, s]), state, False)


def _did_hi_lo(did: int) -> tuple:
    return (did >> 8) & 0xFF, did & 0xFF


def _rdbi(state: _InlineEcuState, did: int) -> Optional[bytes]:
    """Read a single DID; returns full raw response."""
    hi, lo = _did_hi_lo(did)
    return _req(state, bytes([SID_READ_DATA_BY_ID, hi, lo]))


def _wdbi(state: _InlineEcuState, did: int, data: bytes) -> Optional[bytes]:
    hi, lo = _did_hi_lo(did)
    return _req(state, bytes([SID_WRITE_DATA_BY_ID, hi, lo]) + data)


def _rdbi_payload(state: _InlineEcuState, did: int) -> bytes:
    """Return only the data bytes from a successful RDBI response."""
    resp = _rdbi(state, did)
    assert resp is not None and resp[0] == 0x62, f"RDBI 0x{did:04X} failed: {resp}"
    return bytes(resp[3:])  # strip 0x62 + DID bytes


# ---------------------------------------------------------------------------
# DID Data Integrity
# ---------------------------------------------------------------------------

class TestDIDDataIntegrity:
    """Verify that WDBI stores values and RDBI retrieves them exactly."""

    def test_wdbi_rdbi_round_trip_arbitrary_pattern(self):
        """Written bytes must be returned exactly on subsequent RDBI."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        pattern = bytes([0x01, 0x02, 0x03, 0x04, 0x05,
                         0x06, 0x07, 0x08, 0x09, 0x0A, 0x0B])
        resp = _wdbi(state, DID_SPARE_PART, pattern)
        assert resp is not None and resp[0] == 0x6E, f"WDBI must return 0x6E, got {resp}"
        assert _rdbi_payload(state, DID_SPARE_PART) == pattern

    def test_wdbi_rdbi_round_trip_all_zeros(self):
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        data = bytes(11)
        _wdbi(state, DID_SPARE_PART, data)
        assert _rdbi_payload(state, DID_SPARE_PART) == data

    def test_wdbi_rdbi_round_trip_all_ff(self):
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        data = bytes([0xFF] * 11)
        _wdbi(state, DID_SPARE_PART, data)
        assert _rdbi_payload(state, DID_SPARE_PART) == data

    def test_wdbi_second_write_overwrites_first(self):
        """Subsequent writes must replace previous stored value."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        _wdbi(state, DID_SPARE_PART, bytes([0xAA] * 11))
        second = bytes([0xBB] * 11)
        _wdbi(state, DID_SPARE_PART, second)
        assert _rdbi_payload(state, DID_SPARE_PART) == second

    def test_wdbi_does_not_affect_sibling_dids(self):
        """Writing F187 must not change F190 or F18C."""
        state = _sim()
        vin_before    = _rdbi_payload(state, DID_VIN)
        serial_before = _rdbi_payload(state, DID_ECU_SERIAL)
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        _wdbi(state, DID_SPARE_PART, bytes([0x55] * 11))
        assert _rdbi_payload(state, DID_VIN)        == vin_before
        assert _rdbi_payload(state, DID_ECU_SERIAL) == serial_before

    def test_initial_did_store_is_0xAA(self):
        """Fresh simulator state must return 0xAA bytes for every DID."""
        state = _sim()
        assert _rdbi_payload(state, DID_VIN)        == bytes([0xAA] * 17)
        assert _rdbi_payload(state, DID_ECU_SERIAL) == bytes([0xAA] * 4)
        assert _rdbi_payload(state, DID_CUSTOM_0C)  == bytes([0xAA] * 2)
        assert _rdbi_payload(state, DID_CUSTOM_05)  == bytes([0xAA] * 1)

    def test_rdbi_vin_response_total_length(self):
        """RDBI for VIN (17 bytes): total response must be 1 + 2 + 17 = 20 bytes."""
        resp = _rdbi(_sim(), DID_VIN)
        assert resp is not None and resp[0] == 0x62
        assert len(resp) == 20, f"Expected 20 bytes, got {len(resp)}"
        assert resp[1] == 0xF1 and resp[2] == 0x90

    def test_rdbi_single_byte_did_total_length(self):
        """RDBI for 1-byte DID 0x0500: total response must be 1 + 2 + 1 = 4 bytes."""
        resp = _rdbi(_sim(), DID_CUSTOM_05)
        assert resp is not None and resp[0] == 0x62
        assert len(resp) == 4, f"Expected 4 bytes, got {len(resp)}"

    def test_rdbi_multi_did_single_pdu(self):
        """Multi-DID request: VIN + ECUSerial in one PDU → both DIDs in response."""
        state = _sim()
        resp = _req(state, bytes([SID_READ_DATA_BY_ID,
                                   0xF1, 0x90,   # VIN
                                   0xF1, 0x8C]))  # ECUSerial
        assert resp is not None and resp[0] == 0x62
        # 1(0x62) + 2+17(VIN) + 2+4(ECUSerial) = 26
        assert len(resp) == 26, f"Multi-DID response length wrong: {len(resp)}"

    def test_rdbi_multi_did_preserves_request_order(self):
        """Multi-DID response echoes DIDs in the order they were requested."""
        state = _sim()
        # Request ECUSerial first, then VIN
        resp = _req(state, bytes([SID_READ_DATA_BY_ID,
                                   0xF1, 0x8C,   # ECUSerial first
                                   0xF1, 0x90]))  # VIN second
        assert resp is not None and resp[0] == 0x62
        assert resp[1] == 0xF1 and resp[2] == 0x8C, "First DID in response must be F18C"
        assert resp[1 + 2 + 4] == 0xF1 and resp[1 + 2 + 4 + 1] == 0x90

    def test_wdbi_readonly_did_returns_nrc_31(self):
        """WDBI to a read-only DID (F190) must return NRC 0x31."""
        resp = _req(_sim(), bytes([SID_WRITE_DATA_BY_ID, 0xF1, 0x90]) + bytes([0xAA] * 17))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_REQUEST_OUT_OF_RANGE

    def test_wdbi_wrong_data_length_returns_nrc_13(self):
        """WDBI with wrong data count must return NRC 0x13."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        resp = _wdbi(state, DID_SPARE_PART, bytes([0xAA] * 10))  # needs 11
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INCORRECT_MSG_LEN

    def test_wdbi_positive_response_echoes_did_bytes(self):
        """WDBI positive response (0x6E) must echo back the DID identifier bytes."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        resp = _wdbi(state, DID_SPARE_PART, bytes(11))
        assert resp is not None and resp[0] == 0x6E
        assert resp[1] == 0xF1 and resp[2] == 0x87


# ---------------------------------------------------------------------------
# DTC Lifecycle
# ---------------------------------------------------------------------------

class TestDTCLifecycle:
    """Set DTC status → read with 0x19 → clear with 0x14 → verify cleared."""

    # basic_ecu DTC codes (decimal, as stored in state.dtcs)
    CODE_0 = 0xC00100   # 12583168
    CODE_1 = 0xC00200   # 12583424

    def _set_dtc(self, state: _InlineEcuState, idx: int, status: int) -> None:
        state.dtcs[idx]['status'] = status

    def _read_dtc_sub02(self, state: _InlineEcuState, mask: int = 0xFF) -> bytes:
        resp = _req(state, bytes([SID_READ_DTC_INFO, 0x02, mask]))
        assert resp is not None and resp[0] == 0x59 and resp[1] == 0x02
        return resp

    def test_dtc_status_initially_zero(self):
        state = _sim()
        for d in state.dtcs:
            assert d['status'] == 0x00

    def test_dtc_visible_in_sub02_after_status_set(self):
        """Setting DTC status → it must appear in 0x19/0x02 with correct code."""
        state = _sim()
        self._set_dtc(state, 0, 0x08)
        resp = self._read_dtc_sub02(state, mask=0x08)
        records_payload = resp[3:]
        assert len(records_payload) == 4, "Exactly one DTC record expected"
        code = (records_payload[0] << 16) | (records_payload[1] << 8) | records_payload[2]
        assert code == self.CODE_0
        assert records_payload[3] == 0x08

    def test_dtc_mask_excludes_non_matching_dtcs(self):
        """Only DTCs whose status byte has the mask bit set appear in response."""
        state = _sim()
        self._set_dtc(state, 0, 0x08)   # testFailed — matches mask 0x08
        self._set_dtc(state, 1, 0x02)   # pending     — does NOT match mask 0x08
        resp = self._read_dtc_sub02(state, mask=0x08)
        payload_len = len(resp) - 3
        assert payload_len == 4, f"Expected 1 DTC record (4 bytes), got {payload_len // 4}"

    def test_sub01_count_matches_sub02_record_count(self):
        """NumberOfDTC from 0x19/0x01 must equal record count from 0x19/0x02."""
        state = _sim()
        self._set_dtc(state, 0, 0x08)
        self._set_dtc(state, 1, 0x08)
        mask = 0x08
        resp01 = _req(state, bytes([SID_READ_DTC_INFO, 0x01, mask]))
        assert resp01 is not None and resp01[1] == 0x01
        count = (resp01[4] << 8) | resp01[5]
        resp02 = self._read_dtc_sub02(state, mask)
        records = (len(resp02) - 3) // 4
        assert count == records == 2

    def test_dtc_lifecycle_set_clear_verify_zero(self):
        """Full lifecycle: set active → 0x14 clear → 0x19/0x02 returns empty list."""
        state = _sim()
        state.session = SESSION_EXTENDED
        self._set_dtc(state, 0, 0x08)
        # Verify active
        resp = self._read_dtc_sub02(state, mask=0x08)
        assert len(resp) > 3
        # Clear all DTCs
        clear_resp = _req(state, bytes([SID_CLEAR_DTC, 0xFF, 0xFF, 0xFF]))
        assert clear_resp is not None and clear_resp[0] == 0x54
        # Verify cleared — payload should now be empty (only header bytes)
        resp2 = self._read_dtc_sub02(state, mask=0x08)
        assert len(resp2) == 3, "No DTC records expected after clear"

    def test_both_dtcs_cleared_by_single_0x14(self):
        """A single 0x14 must zero out all DTCs, not just one."""
        state = _sim()
        state.session = SESSION_EXTENDED
        self._set_dtc(state, 0, 0x08)
        self._set_dtc(state, 1, 0x04)
        _req(state, bytes([SID_CLEAR_DTC, 0xFF, 0xFF, 0xFF]))
        for d in state.dtcs:
            assert d['status'] == 0x00

    def test_clear_dtc_in_default_session_returns_nrc_7f(self):
        state = _sim()
        resp = _req(state, bytes([SID_CLEAR_DTC, 0xFF, 0xFF, 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION

    def test_dtc_status_byte_preserved_exactly(self):
        """Multi-bit status byte must be returned verbatim from 0x19/0x02."""
        state = _sim()
        state.session = SESSION_EXTENDED
        self._set_dtc(state, 0, 0x2F)
        resp = self._read_dtc_sub02(state, mask=0xFF)
        code_start = 3
        assert resp[code_start + 3] == 0x2F, \
            f"Expected status 0x2F, got {resp[code_start + 3]:#04x}"

    def test_clear_dtc_does_not_corrupt_did_store(self):
        """DID reads must work correctly after 0x14 ClearDTC."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        pattern = bytes([0x11, 0x22, 0x33, 0x44, 0x55,
                         0x66, 0x77, 0x88, 0x99, 0xAA, 0xBB])
        _wdbi(state, DID_SPARE_PART, pattern)
        _req(state, bytes([SID_CLEAR_DTC, 0xFF, 0xFF, 0xFF]))
        assert _rdbi_payload(state, DID_SPARE_PART) == pattern


# ---------------------------------------------------------------------------
# Session and Security State Isolation
# ---------------------------------------------------------------------------

class TestSessionSecurityIsolation:
    """State cleared on session change and ECU reset; persists within session."""

    def test_session_change_clears_security_unlock(self):
        """DiagnosticSessionControl must revoke any active security unlock."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        _session(state, SESSION_DEFAULT)
        assert not state.sec_unlocked.get(1)

    def test_session_change_clears_pending_seed(self):
        """Pending seed must be discarded when session changes."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        _req(state, bytes([SID_SECURITY_ACCESS, 0x01]))  # requestSeed — leaves pending
        assert state.pending_seed is not None
        _session(state, SESSION_DEFAULT)
        assert state.pending_seed is None

    def test_ecu_reset_drops_session_to_default(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert state.session == SESSION_EXTENDED
        _req(state, bytes([SID_ECU_RESET, 0x01]))
        assert state.session == SESSION_DEFAULT

    def test_ecu_reset_clears_security_unlock(self):
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        _req(state, bytes([SID_ECU_RESET, 0x01]))
        assert not state.sec_unlocked.get(1)

    def test_ecu_reset_clears_fail_counter(self):
        """Security fail count must reset on ECU reset (lockout window lifts)."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        state.sec_fail_count[1] = 3
        _req(state, bytes([SID_ECU_RESET, 0x01]))
        assert state.sec_fail_count.get(1, 0) == 0

    def test_security_unlock_persists_within_session(self):
        """Once unlocked, subsequent requests within the same session see the unlock."""
        state = _sim()
        state.session = SESSION_EXTENDED
        state.sec_unlocked[1] = True
        for _ in range(3):
            resp = _rdbi(state, DID_SPARE_PART)
            assert resp is not None and resp[0] == 0x62

    def test_fresh_state_has_no_security_unlock(self):
        state = _sim()
        assert not any(state.sec_unlocked.values())

    def test_did_with_extended_min_session_blocked_in_default(self):
        """DID F187 (min_session=extended) must return NRC 0x7F in default session."""
        state = _sim()
        resp = _rdbi(state, DID_SPARE_PART)
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION

    def test_did_with_extended_min_session_accessible_in_extended(self):
        state = _sim()
        state.session = SESSION_EXTENDED
        resp = _rdbi(state, DID_SPARE_PART)
        assert resp is not None and resp[0] == 0x62


# ---------------------------------------------------------------------------
# Protocol Response Format
# ---------------------------------------------------------------------------

class TestResponseFormatCorrectness:
    """Verify that positive responses carry the correct bytes in the correct positions."""

    def test_dsc_response_format_and_timing_bytes(self):
        """0x50 response must carry sub-function + P2 (2 bytes) + P2* (2 bytes)."""
        state = _sim()
        resp = _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_EXTENDED]))
        assert resp is not None and resp[0] == 0x50
        assert resp[1] == SESSION_EXTENDED
        assert len(resp) == 6, f"DSC response must be 6 bytes, got {len(resp)}"

    def test_routine_control_response_echoes_rid(self):
        """0x71 response must echo sub-function + RID bytes verbatim."""
        state = _sim()
        state.session = SESSION_EXTENDED
        rid_hi, rid_lo = 0xFF, 0x00
        resp = _req(state, bytes([SID_ROUTINE_CONTROL, 0x01, rid_hi, rid_lo]))
        assert resp is not None and resp[0] == 0x71
        assert resp[1] == 0x01
        assert resp[2] == rid_hi and resp[3] == rid_lo

    def test_tester_present_response_format(self):
        """0x7E response to TesterPresent must carry echo of sub-function 0x00."""
        state = _sim()
        resp = _req(state, bytes([SID_TESTER_PRESENT, 0x00]))
        assert resp is not None and resp[0] == 0x7E
        assert resp[1] == 0x00

    def test_ecu_reset_response_echoes_reset_type(self):
        """0x51 response must echo the resetType sub-function."""
        state = _sim()
        resp = _req(state, bytes([SID_ECU_RESET, 0x01]))
        assert resp is not None and resp[0] == 0x51
        assert resp[1] == 0x01
